// VULNERABLE
document.getElementById('target').innerHTML = window.location.hash.slice(1);

// SAFE - plain text only
document.getElementById('target').textContent = window.location.hash.slice(1);

// SAFE - if HTML rendering is required
import DOMPurify from 'dompurify';
document.getElementById('target').innerHTML = DOMPurify.sanitize(window.location.hash.slice(1));

# Nginx example - strict CSP with nonce-based inline script allowance
add_header Content-Security-Policy "
  default-src 'self';
  script-src 'self' 'nonce-{RANDOM_NONCE}';
  style-src 'self' 'nonce-{RANDOM_NONCE}';
  img-src 'self' data: https:;
  connect-src 'self' https://api.moneybird.com;
  frame-ancestors 'none';
  base-uri 'self';
  form-action 'self';
  upgrade-insecure-requests;
" always;

# Start with report-only to test:
add_header Content-Security-Policy-Report-Only "default-src 'self'; report-uri /csp-report" always;

// VULNERABLE
window.addEventListener('message', function(event) {
  processData(event.data); // no origin check
});

// SAFE
const ALLOWED_ORIGINS = ['https://www.moneybird.com', 'https://app.moneybird.com'];

window.addEventListener('message', function(event) {
  if (!ALLOWED_ORIGINS.includes(event.origin)) {
    console.warn('Rejected postMessage from untrusted origin:', event.origin);
    return;
  }
  processData(event.data);
});

// For actual state-mutating endpoints, use idempotency keys:
// Client sends: POST /api/invoices with header Idempotency-Key: <uuid>
// Server stores the key and result; duplicate requests return cached result

// Database-level protection example (PostgreSQL advisory lock):
BEGIN;
SELECT pg_advisory_xact_lock(hashtext('invoice_create_' || user_id));
-- perform state mutation safely
COMMIT;
